11: // Initialize provides the migrator singleton with required dependencies and builds the map of migrations.
12: func Initialize(dsInfoProvider schemaversion.DataSourceInfoProvider) {
13: 	migratorInstance.init(dsInfoProvider)
14: }
15: 
16: // ResetForTesting resets the migrator singleton for testing purposes.
17: func ResetForTesting() {
18: 	migratorInstance = &migrator{
19: 		migrations: map[int]schemaversion.SchemaVersionMigrationFunc{},
20: 		ready:      make(chan struct{}),
21: 	}
22: 	initOnce = sync.Once{}
23: }
24: 
25: // Migrate migrates the given dashboard to the target version.
26: // This will block until the migrator is initialized.
27: func Migrate(ctx context.Context, dash map[string]interface{}, targetVersion int) error {
28: 	return migratorInstance.migrate(ctx, dash, targetVersion)
29: }
30: 
31: var (
32: 	migratorInstance = &migrator{
33: 		migrations: map[int]schemaversion.SchemaVersionMigrationFunc{},
34: 		ready:      make(chan struct{}),
